// ---- Automa JS Environment Diagnostic ----
var env = {
  hasDocument:       typeof document         !== 'undefined',
  hasAutomaNext:     typeof automaNextBlock   !== 'undefined',
  hasAutomaSet:      typeof automaSetVariable !== 'undefined',
  hasAutomaRef:      typeof automaRefData     !== 'undefined',
  url:               typeof location         !== 'undefined' ? location.href : '(no location)',
  title:             typeof document         !== 'undefined' ? document.title : '(no document)'
};

var msg = '[Automa Debug]\n'
  + 'document: '        + env.hasDocument     + '\n'
  + 'automaNextBlock: ' + env.hasAutomaNext    + '\n'
  + 'automaSetVariable: '+ env.hasAutomaSet   + '\n'
  + 'automaRefData: '   + env.hasAutomaRef     + '\n'
  + 'URL: '             + env.url             + '\n'
  + 'Title: '           + env.title;

// Show as alert so it's impossible to miss
alert(msg);

// Also log to browser console
console.log(msg);

// Advance the workflow if the function is available
if (typeof automaNextBlock === 'function') {
  automaNextBlock({ data: JSON.stringify(env) });
}
// If automaNextBlock is NOT available, the block will time out (10s).
// The alert() will still have appeared, which is the key diagnostic signal.
